25	    /// All mutable UI state for the pack editor panel.
26	    pub struct PackEditorState {
27	        pub editor: PackEditor,
28	        pub profile_dir: PathBuf,
29	        pub selected_category: Option<String>,
30	        pub selected_macro: Option<String>,
31	        /// Form input: macro name.
32	        pub form_name: String,
33	        /// Form input: trigger phrase.
34	        pub form_phrase: String,
35	        /// Form input: if_flag gate condition.
36	        pub form_if_flag: String,
37	        /// Form input: set_flag side effect.
38	        pub form_set_flag: String,
39	        /// Form input: comma-separated key sequence.
40	        pub form_keys: String,
41	        /// True while the category rename confirmation UI is visible.
42	        pub show_rename_warning: bool,
43	        /// Staging field for the new category name in Add Category toolbar.
44	        pub form_new_category: String,
45	        /// True after the first "Remove Macro" click — shows confirm button.
46	        pub pending_remove_macro: bool,
47	        /// Last synchronous error to surface inline in the panel.
48	        pub last_error: Option<String>,
49	        /// Set to the imported pack name after a successful Import Pack; caller drains each frame.
50	        pub imported_pack_name: Option<String>,
51	    }
52	
53	    impl PackEditorState {
54	        pub fn new(editor: PackEditor, profile_dir: PathBuf) -> Self {
55	            Self {
56	                editor,
57	                profile_dir,
58	                selected_category: None,
59	                selected_macro: None,
60	                form_name: String::new(),
61	                form_phrase: String::new(),
62	                form_if_flag: String::new(),
63	                form_set_flag: String::new(),
64	                form_keys: String::new(),
65	                show_rename_warning: false,
66	                form_new_category: String::new(),
67	                pending_remove_macro: false,
68	                last_error: None,
69	                imported_pack_name: None,
70	            }
71	        }
72	
73	        /// Save the pack to disk then notify the daemon via SwitchProfile.
74	        ///
75	        /// Returns Ok if the disk write succeeded. Daemon notification failure is
76	        /// logged as a warning but does not make the overall save fail.
77	        pub fn save(&self) -> anyhow::Result<()> {
78	            let pack = self.editor.pack();
79	            pack.save_to_dir(&self.profile_dir)?;
80	
81	            let macro_count = pack.categories.iter().map(|c| c.macros.len()).sum::<usize>();
82	            let path = self.profile_dir.display().to_string();
83	            tracing::info!(path, macro_count, "pack saved");
84	
85	            let name = pack.name.clone();
86	            if let Err(e) = send_command(ControlRequest::SwitchProfile { name }) {
87	                let reason = e.to_string();
88	                tracing::warn!(reason, "SwitchProfile dispatch failed");
89	            }
90	
91	            Ok(())
92	        }
93	    }
