95	    /// Render the full pack editor panel.
96	    pub fn show_pack_editor(ui: &mut egui::Ui, state: &mut PackEditorState) {
97	        ui.heading(format!("Pack Editor — {}", state.editor.pack().name));
98	
99	        // ── Category toolbar ─────────────────────────────────────────────────
100	        ui.horizontal(|ui| {
101	            ui.label("New category:");
102	            ui.text_edit_singleline(&mut state.form_new_category);
103	
104	            if ui.button("Add Category").clicked() {
105	                let name = state.form_new_category.trim().to_string();
106	                match state.editor.add_category(&name) {
107	                    Ok(()) => {
108	                        state.last_error = None;
109	                        state.form_new_category.clear();
110	                    }
111	                    Err(e) => state.last_error = Some(e.to_string()),
112	                }
113	            }
114	
115	            // Remove Category: only offered when a category is selected.
116	            if let Some(cat_name) = state.selected_category.clone() {
117	                if ui.button("Remove Category").clicked() {
118	                    match state.editor.remove_category(&cat_name) {
119	                        Ok(()) => {
120	                            state.last_error = None;
121	                            state.selected_category = None;
122	                            state.selected_macro = None;
123	                        }
124	                        Err(e) => state.last_error = Some(e.to_string()),
125	                    }
126	                }
127	
128	                // Rename Category (with two-click confirmation).
129	                if ui.button("Rename Category").clicked() {
130	                    state.show_rename_warning = true;
131	                }
132	
133	                if state.show_rename_warning {
134	                    ui.colored_label(
135	                        egui::Color32::YELLOW,
136	                        "⚠ if_flag/set_flag references are NOT updated — confirm rename?",
137	                    );
138	                    let new_name = state.form_new_category.trim().to_string();
139	                    if ui.button("Confirm Rename").clicked() && !new_name.is_empty() {
140	                        match state.editor.rename_category(&cat_name, &new_name) {
141	                            Ok(()) => {
142	                                state.last_error = None;
143	                                state.selected_category = Some(new_name.clone());
144	                                state.form_new_category.clear();
145	                                state.show_rename_warning = false;
146	                            }
147	                            Err(e) => {
148	                                state.last_error = Some(e.to_string());
149	                                state.show_rename_warning = false;
150	                            }
151	                        }
152	                    }
153	                    if ui.button("Cancel").clicked() {
154	                        state.show_rename_warning = false;
155	                    }
156	                }
157	            }
158	
159	            // ── Import / Export Pack ─────────────────────────────────────────
160	            if ui.button("Import Pack").clicked() {
161	                if let Some(path) = FileDialog::new()
162	                    .add_filter("Pack", &["hdpack"])
163	                    .pick_file()
164	                {
165	                    match get_profiles_dir() {
166	                        Ok(profiles_dir) => match Pack::import_to(&path, &profiles_dir) {
167	                            Ok(pack) => {
168	                                let pack_name = pack.name.clone();
169	                                let macro_count: usize =
170	                                    pack.categories.iter().map(|c| c.macros.len()).sum();
171	                                tracing::info!(
172	                                    zip_path = %path.display(),
173	                                    pack_name = %pack_name,
174	                                    macro_count,
175	                                    "Import Pack: succeeded"
176	                                );
177	                                let new_profile_dir = profiles_dir.join(&pack_name);
178	                                state.editor = PackEditor::new(pack);
179	                                state.profile_dir = new_profile_dir;
180	                                state.selected_category = None;
181	                                state.selected_macro = None;
182	                                state.last_error = None;
183	                                state.imported_pack_name = Some(pack_name);
184	                            }
185	                            Err(e) => {
186	                                let reason = e.to_string();
187	                                tracing::warn!(reason, "Import Pack: failed");
188	                                state.last_error = Some(reason);
189	                            }
190	                        },
191	                        Err(e) => {
192	                            let reason = e.to_string();
193	                            tracing::warn!(reason, "Import Pack: could not resolve profiles dir");
194	                            state.last_error = Some(reason);
195	                        }
196	                    }
197	                }
198	            }
199	
200	            if ui.button("Export Pack").clicked() {
201	                let pack_name = state.editor.pack().name.clone();
202	                let default_filename = format!("{pack_name}.hdpack");
203	                if let Some(dest_path) = FileDialog::new()
204	                    .add_filter("Pack", &["hdpack"])
205	                    .set_file_name(&default_filename)
206	                    .save_file()
207	                {
208	                    match state.editor.pack().export(&state.profile_dir, &dest_path) {
209	                        Ok(()) => {
210	                            let macro_count: usize = state
211	                                .editor
212	                                .pack()
213	                                .categories
214	                                .iter()
215	                                .map(|c| c.macros.len())
216	                                .sum();
217	                            tracing::info!(
218	                                dest_path = %dest_path.display(),
219	                                pack_name = %pack_name,
220	                                macro_count,
221	                                "Export Pack: succeeded"
222	                            );
223	                            state.last_error = None;
224	                        }
225	                        Err(e) => {
226	                            let reason = e.to_string();
227	                            tracing::warn!(reason, "Export Pack: failed");
228	                            state.last_error = Some(reason);
229	                        }
230	                    }
231	                }
232	            }
233	        });
234	
235	        ui.add_space(4.0);
236	
237	        // ── Three-column layout ───────────────────────────────────────────────
238	        // Clone lists before the egui closures to avoid simultaneous mut borrows.
239	        let category_names: Vec<String> =
240	            state.editor.pack().categories.iter().map(|c| c.name.clone()).collect();
241	
242	        let macro_names: Vec<String> = state
243	            .selected_category
244	            .as_deref()
245	            .and_then(|cat| state.editor.pack().categories.iter().find(|c| c.name == cat))
246	            .map(|cat| cat.macros.iter().map(|m| m.name.clone()).collect())
247	            .unwrap_or_default();
248	
249	        // Snapshot current macro's MacroConfig for form pre-population (read-only borrow ends here).
250	        let selected_macro_config: Option<MacroConfig> = state
251	            .selected_category
252	            .as_deref()
253	            .zip(state.selected_macro.as_deref())
254	            .and_then(|(cat, mac)| {
255	                state
256	                    .editor
257	                    .pack()
258	                    .categories
259	                    .iter()
260	                    .find(|c| c.name == cat)
261	                    .and_then(|c| c.macros.iter().find(|m| m.name == mac))
262	                    .cloned()
263	            });
264	
265	        ui.horizontal(|ui| {
266	            // ── Left: category list ─────────────────────────────────────────
267	            ui.vertical(|ui| {
268	                ui.set_min_width(140.0);
269	                ui.label("Categories");
270	                egui::ScrollArea::vertical()
271	                    .id_salt("cat_scroll")
272	                    .max_height(300.0)
273	                    .show(ui, |ui| {
274	                        for cat_name in &category_names {
275	                            let selected =
276	                                state.selected_category.as_deref() == Some(cat_name.as_str());
277	                            if ui.selectable_label(selected, cat_name.as_str()).clicked() {
278	                                if state.selected_category.as_deref() != Some(cat_name.as_str()) {
279	                                    state.selected_category = Some(cat_name.clone());
280	                                    state.selected_macro = None;
281	                                    state.pending_remove_macro = false;
282	                                }
283	                            }
284	                        }
285	                    });
286	            });
287	
288	            ui.separator();
289	
290	            // ── Middle: macro list ──────────────────────────────────────────
291	            ui.vertical(|ui| {
292	                ui.set_min_width(160.0);
293	                ui.label("Macros");
294	                egui::ScrollArea::vertical()
295	                    .id_salt("macro_scroll")
296	                    .max_height(300.0)
297	                    .show(ui, |ui| {
298	                        for mac_name in &macro_names {
299	                            let selected =
300	                                state.selected_macro.as_deref() == Some(mac_name.as_str());
301	                            if ui.selectable_label(selected, mac_name.as_str()).clicked() {
302	                                if state.selected_macro.as_deref() != Some(mac_name.as_str()) {
303	                                    state.selected_macro = Some(mac_name.clone());
304	                                    state.pending_remove_macro = false;
305	                                    // Populate form from the just-selected macro.
306	                                    if let Some(cat) = state.selected_category.as_deref() {
307	                                        if let Some(m) = state
308	                                            .editor
309	                                            .pack()
310	                                            .categories
311	                                            .iter()
312	                                            .find(|c| c.name == cat)
313	                                            .and_then(|c| {
314	                                                c.macros.iter().find(|m| m.name == *mac_name)
315	                                            })
316	                                        {
317	                                            state.form_name = m.name.clone();
318	                                            state.form_phrase =
319	                                                m.phrase.clone().unwrap_or_default();
320	                                            state.form_if_flag =
321	                                                m.if_flag.clone().unwrap_or_default();
322	                                            state.form_set_flag =
323	                                                m.set_flag.clone().unwrap_or_default();
324	                                            state.form_keys = m
325	                                                .keys
326	                                                .iter()
327	                                                .map(|k| k.key.as_str())
328	                                                .collect::<Vec<_>>()
329	                                                .join(", ");
330	                                        }
331	                                    }
332	                                }
333	                            }
334	                        }
335	                    });
336	            });
337	
338	            ui.separator();
339	
340	            // ── Right: edit form ────────────────────────────────────────────
341	            ui.vertical(|ui| {
342	                ui.set_min_width(220.0);
343	                ui.label("Edit Macro");
344	
345	                egui::Grid::new("macro_form_grid")
346	                    .num_columns(2)
347	                    .spacing([8.0, 4.0])
348	                    .show(ui, |ui| {
349	                        ui.label("Name:");
350	                        ui.text_edit_singleline(&mut state.form_name);
351	                        ui.end_row();
352	
353	                        ui.label("Phrase:");
354	                        ui.text_edit_singleline(&mut state.form_phrase);
355	                        ui.end_row();
356	
357	                        ui.label("If flag:");
358	                        ui.text_edit_singleline(&mut state.form_if_flag);
359	                        ui.end_row();
360	
361	                        ui.label("Set flag:");
362	                        ui.text_edit_singleline(&mut state.form_set_flag);
363	                        ui.end_row();
364	
365	                        ui.label("Keys:");
366	                        ui.text_edit_singleline(&mut state.form_keys);
367	                        ui.end_row();
368	                    });
369	
370	                // Per-key dwell/gap overrides (rendered for selected macro only).
371	                if let Some(ref mc) = selected_macro_config {
372	                    if !mc.keys.is_empty() {
373	                        ui.add_space(4.0);
374	                        ui.label("Key timing overrides (edit macro to apply):");
375	                        for ka in &mc.keys {
376	                            ui.horizontal(|ui| {
377	                                ui.monospace(ka.key.as_str());
378	                                ui.label(format!(
379	                                    "dwell: {} ms   gap: {} ms",
380	                                    ka.dwell_ms.map_or("default".into(), |v| v.to_string()),
381	                                    ka.gap_ms.map_or("default".into(), |v| v.to_string()),
382	                                ));
383	                            });
384	                        }
385	                    }
386	                }
387	
388	                ui.add_space(6.0);
389	
390	                // CRUD buttons.
391	                ui.horizontal(|ui| {
392	                    // Add Macro.
393	                    if ui.button("Add Macro").clicked() {
394	                        if let Some(cat) = state.selected_category.clone() {
395	                            match build_macro_config_from_form(
396	                                &state.form_name,
397	                                &state.form_phrase,
398	                                &state.form_if_flag,
399	                                &state.form_set_flag,
400	                                &state.form_keys,
401	                            ) {
402	                                Ok(mc) => match state.editor.add_macro(&cat, mc) {
403	                                    Ok(()) => state.last_error = None,
404	                                    Err(e) => state.last_error = Some(e.to_string()),
405	                                },
406	                                Err(e) => state.last_error = Some(e.to_string()),
407	                            }
408	                        } else {
409	                            state.last_error = Some("Select a category first.".into());
410	                        }
411	                    }
412	
413	                    // Update Macro.
414	                    if ui.button("Update Macro").clicked() {
415	                        match (state.selected_category.clone(), state.selected_macro.clone()) {
416	                            (Some(cat), Some(mac)) => {
417	                                match parse_key_sequence(&state.form_keys) {
418	                                    Ok(keys) => {
419	                                        let phrase = opt_from_str(&state.form_phrase);
420	                                        let if_flag = opt_from_str(&state.form_if_flag);
421	                                        let set_flag = opt_from_str(&state.form_set_flag);
422	                                        let updates = crate::pack::MacroUpdates {
423	                                            phrase: Some(phrase),
424	                                            if_flag: Some(if_flag),
425	                                            set_flag: Some(set_flag),
426	                                            sound: None,
427	                                            keys: Some(keys),
428	                                        };
429	                                        match state.editor.edit_macro(&cat, &mac, updates) {
430	                                            Ok(()) => state.last_error = None,
431	                                            Err(e) => {
432	                                                state.last_error = Some(e.to_string())
433	                                            }
434	                                        }
435	                                    }
436	                                    Err(e) => state.last_error = Some(e.to_string()),
437	                                }
438	                            }
439	                            _ => {
440	                                state.last_error =
441	                                    Some("Select a category and macro first.".into())
442	                            }
443	                        }
444	                    }
445	                });
446	
