466	                                            state.form_if_flag.clear();
467	                                            state.form_set_flag.clear();
468	                                            state.form_keys.clear();
469	                                        }
470	                                        Err(e) => {
471	                                            state.last_error = Some(e.to_string());
472	                                            state.pending_remove_macro = false;
473	                                        }
474	                                    }
475	                                }
476	                            }
477	                            if ui.button("Cancel").clicked() {
478	                                state.pending_remove_macro = false;
479	                            }
480	                        } else if ui.button("Remove Macro").clicked() {
481	                            state.pending_remove_macro = true;
482	                        }
483	                    }
484	                });
485	            });
486	        });
