489	
490	        // ── Save button ───────────────────────────────────────────────────────
491	        if ui.button("💾 Save Pack").clicked() {
492	            match state.save() {
493	                Ok(()) => state.last_error = None,
494	                Err(e) => state.last_error = Some(e.to_string()),
495	            }
496	        }
497	
498	        // ── Inline error display ─────────────────────────────────────────────
499	        if let Some(err) = &state.last_error.clone() {
