504	    /// Convert a form string to `Some(s)` when non-empty, `None` to clear the field.
505	    /// Used by Update Macro to produce `Some(None)` (clear) vs `Some(Some(s))` (set).
506	    fn opt_from_str(s: &str) -> Option<String> {
507	        let trimmed = s.trim();
508	        if trimmed.is_empty() { None } else { Some(trimmed.to_string()) }
509	    }
510	}
